require 'spikard'
require 'json'
require 'faraday'

RSpec.describe 'static_files' do
  let(:base_url) { ENV.fetch('TEST_SERVER_URL', 'http://localhost:8080') }
  let(:client) do
    Faraday.new(url: base_url) do |f|
      f.request :json
      f.response :json, content_type: /\bjson$/
    end
  end

  describe 'GET /public/hello.txt' do
    it 'Tests serving a plain text file with Cache-Control headers.' do
      response = client.get('/public/hello.txt')
      expect(response.status).to eq(200)
      expect(response.body).to eq('Hello from static storage')
      expect(response.headers['cache-control']).to eq('public, max-age=60')
      expect(response.headers['content-type']).to eq('text/plain')
    end
  end

  describe 'GET /app/' do
    it 'When index files are enabled the server should serve index.html when the directory root is requested.' do
      response = client.get('/app/')
      expect(response.status).to eq(200)
      expect(response.body).to eq('<!doctype html><h1>Welcome</h1>')
      expect(response.headers['content-type']).to eq('text/html')
    end
  end
end
